class Solution {
public:
    int findIntegers(int n) {
        int res = 0, prev = 0, prevPrev = 0;
        for (int i = 30; i >= 0; --i) {
            int bit = (n >> i) & 1;
            if (bit == 1) {
                res += prevPrev;
                if (prev == 1) prev = 0;
                else prev = 1;
            } else {
                prev = 0;
            }
            prevPrev = prev;
        }
        return res + (prev == 0);
    }
};
